def to_product(model: ProductModel) -> Product:
    return Product(model)


@strawberry.type
class Query:
    @strawberry.field
    def products(self, info: Info) -> List[Product]:
        with Session(engine) as session:
            stmt = (
                select(ProductModel)
                .options(
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.sellers),
                    selectinload(ProductModel.categories),
                    selectinload(ProductModel.images),
                )
                .order_by(ProductModel.id)
            )
            models = session.scalars(stmt).all()
            return [to_product(model) for model in models]

    @strawberry.field
    def product(self, info: Info, id: int) -> Optional[Product]:
        with Session(engine) as session:
            stmt = (
                select(ProductModel)
                .where(ProductModel.id == id)
                .options(
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.sellers),
                    selectinload(ProductModel.categories),
                    selectinload(ProductModel.images),
                )
            )
            model = session.scalars(stmt).first()
            return to_product(model) if model else None


